#include <stdio.h>
#include <math.h>

static long long digit_sum(long long n, long long b) {
    long long s = 0;
    while (n) {
        s += n % b;
        n /= b;
    }
    return s;
}

int main() {
    int Q; if (scanf("%d", &Q)!=1) return 0;
    while (Q--) {
        long long n,l,r; scanf("%lld %lld %lld", &n,&l,&r);
        if (l<=n && n<=r) { printf("%lld\n", n); continue; }
        long long bestB = l;
        long long best = digit_sum(n,l);
        long long up = (long long)sqrt((double)n);
        long long limit = r<up? r: up;
        for (long long B=l; B<=limit; ++B) {
            long long cur = digit_sum(n,B);
            if (cur < best) { best = cur; bestB = B; }
        }
        for (long long q=1; q<=up; ++q) {
            long long B = n / q;
            if (B<l || B>r) continue;
            long long cur = q + n - q*B; // two‑digit sum
            if (cur < best) { best = cur; bestB = B; }
        }
        printf("%lld\n", bestB);
    }
    return 0;
}

