import java.io.*;
import java.util.*;

public class Main {
    private static long digitSum(long n, long b) {
        long s = 0;
        while (n > 0) {
            s += n % b;
            n /= b;
        }
        return s;
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int Q = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (Q-- > 0) {
            long n = fs.nextLong();
            long l = fs.nextLong();
            long r = fs.nextLong();
            if (l <= n && n <= r) {
                out.append(n).append('\n');
                continue;
            }
            long bestB = l;
            long best = digitSum(n, l);
            long sq = (long) Math.sqrt(n);
            long limit = Math.min(r, sq);
            for (long B = l; B <= limit; ++B) {
                long cur = digitSum(n, B);
                if (cur < best) { best = cur; bestB = B; }
            }
            for (long q = 1; q <= sq; ++q) {
                long B = n / q;
                if (B < l || B > r) continue;
                long cur = q + n - q * B; // two‑digit sum
                if (cur < best) { best = cur; bestB = B; }
            }
            out.append(bestB).append('\n');
        }
        System.out.print(out.toString());
    }
    // Fast scanner for speed
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException { return Long.parseLong(next()); }
        int nextInt() throws IOException { return Integer.parseInt(next()); }
        String next() throws IOException {
            StringBuilder sb = new StringBuilder();
            int c;
            while ((c = readByte()) != -1 && c <= ' ') {}
            while (c != -1 && c > ' ') {
                sb.append((char) c);
                c = readByte();
            }
            return sb.toString();
        }
    }
}

