import sys, math

def digit_sum(n, b):
    s = 0
    while n:
        s += n % b
        n //= b
    return s

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    Q = int(next(it))
    out_lines = []
    for _ in range(Q):
        n = int(next(it)); l = int(next(it)); r = int(next(it))
        if l <= n <= r:
            out_lines.append(str(n))
            continue
        bestB = l
        best = digit_sum(n, l)
        sq = int(math.isqrt(n))
        limit = min(r, sq)
        for B in range(l, limit+1):
            cur = digit_sum(n, B)
            if cur < best:
                best = cur; bestB = B
        for q in range(1, sq+1):
            B = n // q
            if B < l or B > r:
                continue
            cur = q + n - q*B  # two‑digit sum
            if cur < best:
                best = cur; bestB = B
        out_lines.append(str(bestB))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

